#include <stdio.h>
#include <string.h>
#include <ctype.h>

void trim(char *dst, const char *src) {
    // remove leading spaces
    while (*src && isspace((unsigned char)*src)) src++;
    const char *end = src + strlen(src) - 1;
    while (end >= src && isspace((unsigned char)*end)) end--;
    size_t len = (end >= src) ? (size_t)(end - src + 1) : 0;
    for (size_t i = 0; i < len; ++i) {
        dst[i] = (src[i] == ' ') ? '_' : src[i];
    }
    dst[len] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[200];
    char result[200];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof line, stdin)) break;
        // remove trailing newline if present
        size_t ln = strlen(line);
        if (ln && line[ln-1] == '\n') line[ln-1] = '\0';
        trim(result, line);
        printf("Formatted email: %s\n", result);
    }
    return 0;
}

