#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T + 1):
        s = data[i] if i < len(data) else ''
        trimmed = s.strip()
        formatted = trimmed.replace(' ', '_')
        out_lines.append(f"Formatted email: {formatted}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

